head.script:
window.dataLayer = window.dataLayer || [];
// Consent defaults for GTM/GA4 before app hydration.
window.dataLayer.push({
  event: 'consent_default',
  analytics_storage: 'granted',
  ad_storage: 'denied'
});

/*
 * Add the skeleton scroll-lock class before the browser paints
 * anything. Runs during HTML parse, so by the time  renders,
 * the CSS rule above is already in force — no scrollbar flash.
 *
 * Scoped to widget-hosting routes only so pages like /coverage,
 * /pricing, /help keep their native scrollbar from frame zero.
 *
 * Safety: always removes the class after 800ms, even if React never
 * loads. This covers the edge case of a broken JS bundle — users on
 * a crashed page can still scroll to see error state.
 */
(function () {
  var p = window.location.pathname;
  var isWidgetRoute =
    p === '/' ||
    p === '/buy' ||
    p === '/sell' ||
    p.indexOf('/buy/') === 0 ||
    p.indexOf('/sell/') === 0;
  if (!isWidgetRoute) return;
  document.documentElement.classList.add('swaps-widget-skeleton-lock');
  setTimeout(function () {
    document.documentElement.classList.remove('swaps-widget-skeleton-lock');
  }, 800);
})();

nav.style:
position: fixed;
top: 0;
left: 0;
right: 0;
z-index: 50;
padding: 16px 24px;
background: rgba(255, 255, 255, 0.72);
backdrop-filter: blur(20px);

div.style:
max-width: 1280px;
margin: 0 auto;
display: flex;
align-items: center;
justify-content: space-between;

background: #f5f5f7;
border-radius: 32px;
border: 1px solid #e5e5e7;
padding: 24px;
display: flex;
flex-direction: column;
gap: 24px;

body.script:
(function () {
  var debugEnabled = window.location.search.includes('tgdebug=1');
  if (!debugEnabled) return;
  window.addEventListener('error', function (e) {
    if (window.Telegram && window.Telegram.WebApp) {
      var d = document.createElement('div');
      d.id = 'tg-error-debug';
      d.style.cssText = 'position:fixed;bottom:0;left:0;right:0;background:#1a0000;color:#ff4444;padding:12px;font-size:11px;z-index:99999;max-height:40vh;overflow:auto;font-family:monospace;word-break:break-all;';
      d.textContent = '[ERROR] ' + (e.message || 'unknown') + ' | ' + (e.filename || '?') + ':' + (e.lineno || '?') + ':' + (e.colno || '?');
      document.body.appendChild(d);
    }
  });
  window.addEventListener('unhandledrejection', function (e) {
    if (window.Telegram && window.Telegram.WebApp) {
      var d = document.getElementById('tg-error-debug') || document.createElement('div');
      d.id = 'tg-error-debug';
      d.style.cssText = 'position:fixed;bottom:0;left:0;right:0;background:#1a0000;color:#ff4444;padding:12px;font-size:11px;z-index:99999;max-height:40vh;overflow:auto;font-family:monospace;word-break:break-all;';
      d.textContent += ' [PROMISE] ' + (e.reason && e.reason.message ? e.reason.message : String(e.reason));
      document.body.appendChild(d);
    }
  });
})();

setTimeout(function () {
  var s = document.querySelector('.skeleton-pulse');
  if (s && s.parentNode) s.parentNode.removeChild(s);
}, 8000);
